import React from "react";
import styles from "./cart.module.css";
import Counter from "./counter";
import { useSelector } from "react-redux";

interface CartProps {
  imgSrc: string;
  to: string;
}

const Cart: React.FC<CartProps> = ({ imgSrc, to }) => {
  // Use useSelector to get the cart items from the Redux store
  const cartItems = useSelector((state) => state.cart.items);

  // Calculate the total quantity by summing the quantities of all items
  const totalQuantity = cartItems.reduce(
    (total, item) => total + item.quantity,
    0
  );

  return (
    <>
      <a className={styles.cart} href={to}>
        <img src={imgSrc} width={26} height={26} alt="icon-cart" />
      </a>
      <div className={styles.counter}>
        {totalQuantity > 0 && <Counter count={totalQuantity} />}
      </div>
    </>
  );
};

export default Cart;
